		&strings.Builder{},
	); err != nil {
		t.Fatalf("RunManagerReady error = %v", err)
	}
	loaded := loadManagerState(t, stateFile)
	if loaded.Delivery.QueuedWake != nil || loaded.LastActionCard == nil ||
